using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Set up options with the default reflection-based resolver
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver(),
    WriteIndented = true
};

// ── 1. Strongly-typed metadata retrieval ──────────────────────────
// GetTypeInfo<T>() returns JsonTypeInfo<T> directly — no cast needed.
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Type handled : {personInfo.Type.Name}");
Console.WriteLine($"Kind         : {personInfo.Kind}");
Console.WriteLine($"Properties   : {personInfo.Properties.Count}");
Console.WriteLine();

// Round-trip to prove the metadata works
var json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
Console.WriteLine($"Serialized   : {json}");
var back = JsonSerializer.Deserialize(json, personInfo)!;
Console.WriteLine($"Deserialized : {back}");
Console.WriteLine();

// ── 2. Probe without throwing ─────────────────────────────────────
// TryGetTypeInfo returns false instead of throwing when metadata
// for a type isn't available.

// 2a. Type the resolver CAN handle
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
    Console.WriteLine($"Person metadata found          : {found.Type.Name}");
else
    Console.WriteLine("Person metadata NOT found");

// 2b. Resolver that only knows about Person — won't have Stream
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new PersonOnlyResolver()
};

if (limited.TryGetTypeInfo(typeof(System.IO.Stream), out _))
    Console.WriteLine("Stream metadata found          : (unexpected)");
else
    Console.WriteLine("Stream metadata NOT found      : expected — resolver doesn't cover it");

// ── helpers ───────────────────────────────────────────────────────
record Person(string Name, int Age);

/// A resolver that only provides metadata for <see cref="Person"/>.
sealed class PersonOnlyResolver : IJsonTypeInfoResolver
{
    private readonly DefaultJsonTypeInfoResolver _inner = new();

    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options) =>
        type == typeof(Person) ? _inner.GetTypeInfo(type, options) : null;
}

